// Embedded TTF fonts for Producer PDF generation (see producer.server.ts).
//
// pdf-lib's built-in StandardFonts use WinAnsi encoding, which CANNOT encode
// Polish diacritics (a hard throw on the first "ł") — a real Unicode font
// must be embedded via fontkit instead. These are subsets of Liberation Sans
// (SIL Open Font License 1.1, (c) 2007 Red Hat / 2012 Google), reduced to
// Basic Latin + Latin-1 + Latin Extended-A (full Polish coverage) + common
// punctuation, and renamed per the OFL's Reserved-Font-Name rule for
// modified versions. Regenerate with fonttools/pyftsubset if coverage ever
// needs to grow. Kept as base64 in a .ts module (rather than a bundled
// asset file) so the server-function bundler needs no special asset
// handling — this file is server-only and never ships to the client.

export const DOC_SANS_REGULAR_B64 =
  "";

export const DOC_SANS_BOLD_B64 =
  "";
